1	import React, { useState, useRef, DragEvent } from 'react';
2	
3	interface FileUploadProps {
4	  onFilesSelected: (files: File[]) => void;
5	  accept?: string;
6	  maxSizeMB?: number;
7	  multiple?: boolean;
8	  label?: string;
9	}
10	
11	const ALLOWED_TYPES = ['application/pdf', 'image/jpeg', 'image/png'];
12	const ALLOWED_EXTENSIONS = ['.pdf', '.jpg', '.jpeg', '.png'];
13	
14	export default function FileUpload({
15	  onFilesSelected,
16	  accept = '.pdf,.jpg,.jpeg,.png',
17	  maxSizeMB = 10,
18	  multiple = false,
19	  label = 'Upload files',
20	}: FileUploadProps) {
21	  const [isDragging, setIsDragging] = useState(false);
22	  const [error, setError] = useState<string | null>(null);
23	  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
24	  const inputRef = useRef<HTMLInputElement>(null);
25	
26	  function validateFiles(files: FileList | File[]): File[] {
27	    const valid: File[] = [];
28	    const maxBytes = maxSizeMB * 1024 * 1024;
29	
30	    for (const file of Array.from(files)) {
31	      if (!ALLOWED_TYPES.includes(file.type)) {
32	        setError(`Invalid file type: ${file.name}. Allowed: PDF, JPG, PNG`);
33	        return [];
34	      }
35	      if (file.size > maxBytes) {
36	        setError(`File too large: ${file.name}. Max size: ${maxSizeMB}MB`);
37	        return [];
38	      }
39	      valid.push(file);
40	    }
41	    return valid;
42	  }
43	
44	  function handleFiles(files: FileList | File[]) {
45	    setError(null);
46	    const valid = validateFiles(files);
47	    if (valid.length > 0) {
48	      setSelectedFiles(valid);
49	      onFilesSelected(valid);
50	    }
51	  }
52	
53	  function handleDrop(e: DragEvent<HTMLDivElement>) {
54	    e.preventDefault();
55	    setIsDragging(false);
56	    if (e.dataTransfer.files.length) {
57	      handleFiles(e.dataTransfer.files);
58	    }
59	  }
60	
61	  function handleDragOver(e: DragEvent<HTMLDivElement>) {
62	    e.preventDefault();
63	    setIsDragging(true);
64	  }
65	
66	  function handleDragLeave(e: DragEvent<HTMLDivElement>) {
67	    e.preventDefault();
68	    setIsDragging(false);
69	  }
70	
71	  function removeFile(index: number) {
72	    const updated = selectedFiles.filter((_, i) => i !== index);
73	    setSelectedFiles(updated);
74	    onFilesSelected(updated);
75	  }
76	
77	  return (
78	    <div>
79	      <label className="mb-1 block text-sm font-medium text-gray-700">{label}</label>
80	      <div
81	        onDrop={handleDrop}
82	        onDragOver={handleDragOver}
83	        onDragLeave={handleDragLeave}
84	        onClick={() => inputRef.current?.click()}
85	        className={`cursor-pointer rounded-lg border-2 border-dashed p-8 text-center transition-colors ${
86	          isDragging
87	            ? 'border-indigo-400 bg-indigo-50'
88	            : 'border-gray-300 bg-gray-50 hover:border-gray-400'
89	        }`}
90	      >
91	        <svg
92	          className="mx-auto h-10 w-10 text-gray-400"
93	          fill="none"
94	          stroke="currentColor"
95	          viewBox="0 0 24 24"
96	        >
97	          <path
98	            strokeLinecap="round"
99	            strokeLinejoin="round"
100	            strokeWidth={1.5}
101	            d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"
102	          />
103	        </svg>
104	        <p className="mt-2 text-sm text-gray-600">
105	          Drag and drop files here, or <span className="font-medium text-indigo-600">browse</span>
106	        </p>
107	        <p className="mt-1 text-xs text-gray-500">
108	          PDF, JPG, PNG up to {maxSizeMB}MB. Server validates MIME type, file size, and format signature.
109	        </p>
110	        <input
111	          ref={inputRef}
112	          type="file"
113	          accept={accept}
114	          multiple={multiple}
115	          className="hidden"
116	          onChange={(e) => e.target.files && handleFiles(e.target.files)}
117	        />
118	      </div>
119	
120	      {error && (
121	        <p className="mt-2 text-sm text-red-600">{error}</p>
122	      )}
123	
124	      {selectedFiles.length > 0 && (
125	        <ul className="mt-3 space-y-2">
126	          {selectedFiles.map((file, i) => (
127	            <li key={i} className="flex items-center justify-between rounded bg-gray-100 px-3 py-2 text-sm">
128	              <span className="truncate">{file.name} ({(file.size / 1024 / 1024).toFixed(2)} MB)</span>
129	              <button
130	                type="button"
131	                onClick={(e) => { e.stopPropagation(); removeFile(i); }}
132	                className="ml-2 text-red-500 hover:text-red-700"
133	              >
134	                Remove
135	              </button>
136	            </li>
137	          ))}
138	        </ul>
139	      )}
140	    </div>
141	  );
142	}
