14	export async function upload(req: Request, res: Response, next: NextFunction): Promise<void> {
15	  try {
16	    if (!req.file) {
17	      res.status(400).json({ code: 400, msg: 'No file uploaded' });
18	      return;
19	    }
20	    // Validate file type/format/size then store
21	    const attachment = await fileService.validateAndStore({
22	      buffer: req.file.buffer,
23	      originalName: req.file.originalname,
24	      mimeType: req.file.mimetype,
25	      parentType: 'deliverable',
26	      parentId: req.params.jobId,
27	      uploadedBy: req.user!.userId,
28	    });
29	    const deliverable = await deliverableService.upload(
30	      req.params.jobId,
31	      req.user!.userId,
32	      attachment.storagePath,
33	      req.body.copyrightNotice,
34	      req.user!.userId,
35	    );
36	    res.status(201).json(deliverable);
37	  } catch (err) {
38	    next(err);
39	  }
40	}
