1	import fs from 'fs';
2	import path from 'path';
3	import { v4 as uuidv4 } from 'uuid';
4	import { FileAttachment } from '../models';
5	import { config } from '../config';
6	import { ValidationError, NotFoundError } from '../utils/errors';
7	import { validateFileType, validateFileSize, validateFileFormat, sanitizeFilename } from '../utils/documentValidators';
8	import { computeSHA256 } from '../utils/fileChecksum';
9	
10	export interface SaveFileInput {
11	  buffer: Buffer;
12	  originalName: string;
13	  mimeType: string;
14	  parentType: string;
15	  parentId: string;
16	  uploadedBy: string;
17	}
18	
19	/**
20	 * Save a file to the upload directory with a UUID-based filename.
21	 */
22	export async function saveFile(input: SaveFileInput): Promise<{
23	  storagePath: string;
24	  checksum: string;
25	  sizeBytes: number;
26	}> {
27	  const ext = path.extname(input.originalName) || '';
28	  const filename = `${uuidv4()}${ext}`;
29	  const uploadDir = path.resolve(config.uploadDir);
30	
31	  // Ensure upload directory exists
32	  if (!fs.existsSync(uploadDir)) {
33	    fs.mkdirSync(uploadDir, { recursive: true });
34	  }
35	
36	  const storagePath = path.join(uploadDir, filename);
37	
38	  // Prevent path traversal: verify resolved path stays inside upload directory
39	  const resolvedStorage = path.resolve(storagePath);
40	  if (!resolvedStorage.startsWith(uploadDir + path.sep) && resolvedStorage !== uploadDir) {
41	    throw new ValidationError('Invalid storage path');
42	  }
43	
44	  const checksum = computeSHA256(input.buffer);
45	
46	  fs.writeFileSync(resolvedStorage, input.buffer);
47	
48	  return {
49	    storagePath: resolvedStorage,
50	    checksum,
51	    sizeBytes: input.buffer.length,
52	  };
53	}
54	
55	/**
56	 * Validate file and store it with a FileAttachment record.
57	 */
58	export async function validateAndStore(input: SaveFileInput) {
59	  // Validate file
60	  validateFileType(input.mimeType);
61	  validateFileSize(input.buffer.length);
62	  validateFileFormat(input.buffer, input.mimeType);
63	
64	  const sanitized = sanitizeFilename(input.originalName);
65	
66	  // Save to disk
67	  const { storagePath, checksum, sizeBytes } = await saveFile({
68	    ...input,
69	    originalName: sanitized,
70	  });
71	
72	  // Create FileAttachment record
73	  const attachment = await FileAttachment.create({
74	    parentType: input.parentType,
75	    parentId: input.parentId,
76	    originalName: sanitized,
77	    storagePath,
78	    mimeType: input.mimeType,
79	    sizeBytes,
80	    checksum,
81	    uploadedBy: input.uploadedBy,
82	  });
83	
84	  return attachment;
85	}
86	
87	/**
88	 * Retrieve a file by its FileAttachment ID.
89	 * Enforces strict access control: only the uploader, job participants, or admins
90	 * may access the file. Denied attempts are audit-logged.
91	 */
92	export async function getFile(fileId: string, requesterId: string) {
93	  const { checkDocumentAccess } = await import('./documentAccess.service');
94	  const { User } = await import('../models');
95	
96	  // Look up the requester's role from the DB — never trust caller-supplied role
97	  const requester = await User.findById(requesterId);
98	  const requesterRole = requester?.role || 'alumni';
99	
100	  // checkDocumentAccess throws ForbiddenError if denied and audit-logs the denial
101	  const { file: attachment } = await checkDocumentAccess(
102	    fileId,
103	    requesterId,
104	    requesterRole as any,
105	  );
106	
107	  const filePath = attachment.storagePath;
108	  // Prevent path traversal: resolve and verify the path is inside the upload directory
109	  const resolvedPath = path.resolve(filePath);
110	  const uploadRoot = path.resolve(config.uploadDir);
111	  if (!resolvedPath.startsWith(uploadRoot)) {
112	    throw new ValidationError('Invalid file path');
113	  }
114	
115	  if (!fs.existsSync(resolvedPath)) {
116	    throw new NotFoundError('File not found on disk');
117	  }
118	
119	  const buffer = fs.readFileSync(resolvedPath);
120	
121	  return {
122	    buffer,
123	    mimeType: attachment.mimeType,
124	    filename: attachment.originalName,
125	  };
126	}
