1	import { ALLOWED_MIME_TYPES, FILE_MAX_SIZE } from './constants';
2	import { ValidationError } from './errors';
3	
4	export function validateFileType(mimeType: string): void {
5	  if (!ALLOWED_MIME_TYPES.includes(mimeType)) {
6	    throw new ValidationError(`File type ${mimeType} not allowed. Allowed: ${ALLOWED_MIME_TYPES.join(', ')}`);
7	  }
8	}
9	
10	export function validateFileSize(size: number): void {
11	  if (size > FILE_MAX_SIZE) {
12	    throw new ValidationError(`File size ${size} exceeds maximum ${FILE_MAX_SIZE} bytes (10MB)`);
13	  }
14	}
15	
16	export function validateFileFormat(buffer: Buffer, mimeType: string): void {
17	  if (mimeType === 'application/pdf') {
18	    if (buffer.length < 5 || buffer.slice(0, 5).toString() !== '%PDF-') {
19	      throw new ValidationError('Invalid PDF file format');
20	    }
21	  } else if (mimeType === 'image/jpeg') {
22	    if (buffer.length < 2 || buffer[0] !== 0xFF || buffer[1] !== 0xD8) {
23	      throw new ValidationError('Invalid JPEG file format');
24	    }
25	  } else if (mimeType === 'image/png') {
26	    const pngSignature = Buffer.from([0x89, 0x50, 0x4E, 0x47]);
27	    if (buffer.length < 4 || !buffer.slice(0, 4).equals(pngSignature)) {
28	      throw new ValidationError('Invalid PNG file format');
29	    }
30	  }
31	}
32	
33	export function sanitizeFilename(filename: string): string {
34	  return filename
35	    .replace(/[^a-zA-Z0-9._-]/g, '_')
36	    .replace(/\.{2,}/g, '.')
37	    .slice(0, 255);
38	}
