58	export async function validateAndStore(input: SaveFileInput) {
59	  // Validate file
60	  validateFileType(input.mimeType);
61	  validateFileSize(input.buffer.length);
62	  validateFileFormat(input.buffer, input.mimeType);
63	
64	  const sanitized = sanitizeFilename(input.originalName);
65	
66	  // Save to disk
67	  const { storagePath, checksum, sizeBytes } = await saveFile({
68	    ...input,
69	    originalName: sanitized,
70	  });
71	
72	  // Create FileAttachment record
73	  const attachment = await FileAttachment.create({
74	    parentType: input.parentType,
75	    parentId: input.parentId,
76	    originalName: sanitized,
77	    storagePath,
78	    mimeType: input.mimeType,
79	    sizeBytes,
80	    checksum,
81	    uploadedBy: input.uploadedBy,
82	  });
83	
84	  return attachment;
85	}

1	import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
2	import apiClient from '../api/client';
3	import { User } from '../types';
4	
5	interface AuthContextType {
6	  user: User | null;
7	  isAuthenticated: boolean;
8	  login: (username: string, password: string) => Promise<void>;
9	  register: (data: { username: string; email: string; password: string; role?: string }) => Promise<void>;
10	  logout: () => Promise<void>;
11	}
12	
13	const AuthContext = createContext<AuthContextType | undefined>(undefined);
14	
15	export function AuthProvider({ children }: { children: ReactNode }) {
16	  const [user, setUser] = useState<User | null>(() => {
17	    // Use cached user for instant render; will be verified against server below
18	    const stored = localStorage.getItem('user');
19	    return stored ? JSON.parse(stored) : null;
20	  });
21	
22	  const isAuthenticated = !!user;
23	
24	  // On mount, fetch authoritative user profile from server via httpOnly session cookie.
25	  // This replaces any stale/tampered localStorage data with the server's truth.
26	  useEffect(() => {
27	    apiClient.get('/auth/me')
28	      .then(res => {
29	        setUser(res.data);
30	        localStorage.setItem('user', JSON.stringify(res.data));
31	      })
32	      .catch(() => {
33	        // No valid session — clear cached user
34	        localStorage.removeItem('user');
35	        setUser(null);
36	      });
37	  }, []);
38	
39	  async function login(username: string, password: string) {
40	    // Server sets httpOnly cookie; response contains user (no token)
41	    const res = await apiClient.post('/auth/login', { username, password });
42	    const serverUser = res.data.user;
43	    setUser(serverUser);
44	    localStorage.setItem('user', JSON.stringify(serverUser));
45	  }
46	
47	  async function register(data: { username: string; email: string; password: string; role?: string }) {
48	    const res = await apiClient.post('/auth/register', data);
49	    const serverUser = res.data.user;
50	    setUser(serverUser);
51	    localStorage.setItem('user', JSON.stringify(serverUser));
52	  }
53	
54	  async function logout() {
55	    try {
56	      await apiClient.post('/auth/logout'); // Server clears httpOnly cookie
57	    } catch {}
58	    localStorage.removeItem('user');
59	    setUser(null);
60	  }
61	
62	  return (
63	    <AuthContext.Provider value={{ user, isAuthenticated, login, register, logout }}>
64	      {children}
65	    </AuthContext.Provider>
66	  );
67	}
68	
69	export function useAuth() {
70	  const ctx = useContext(AuthContext);
71	  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
72	  return ctx;
73	}
