1	import { Request, Response, NextFunction } from 'express';
2	import jwt from 'jsonwebtoken';
3	import { config } from '../config';
4	import { Session } from '../models/Session';
5	import { User } from '../models/User';
6	import { AuthError } from '../utils/errors';
7	import { AccountStatus } from '../types/enums';
8	
9	const PUBLIC_PATHS = [
10	  'POST:/api/auth/register',
11	  'POST:/api/auth/login',
12	  'GET:/api/health',
13	];
14	
15	export async function authenticate(req: Request, _res: Response, next: NextFunction): Promise<void> {
16	  const routeKey = `${req.method}:${req.path}`;
17	  if (PUBLIC_PATHS.includes(routeKey)) {
18	    return next();
19	  }
20	
21	  try {
22	    // Read token from httpOnly cookie first, fall back to Authorization header
23	    let token: string | undefined;
24	    const cookieHeader = req.headers.cookie;
25	    if (cookieHeader) {
26	      const sessionCookie = cookieHeader.split(';').map(c => c.trim()).find(c => c.startsWith('session='));
27	      if (sessionCookie) token = sessionCookie.split('=')[1];
28	    }
29	    if (!token) {
30	      const authHeader = req.headers.authorization;
31	      if (authHeader?.startsWith('Bearer ')) {
32	        token = authHeader.slice(7);
33	      }
34	    }
35	    if (!token) {
36	      return next(new AuthError('Missing authentication'));
37	    }
38	    let payload: any;
39	    try {
40	      payload = jwt.verify(token, config.jwtSecret);
41	    } catch {
42	      return next(new AuthError('Invalid or expired token'));
43	    }
44	
45	    const session = await Session.findOne({ jti: payload.jti });
46	    if (!session || session.isRevoked) {
47	      return next(new AuthError('Session revoked or expired'));
48	    }
49	
50	    const now = new Date();
51	    if (now > session.absoluteExpiry) {
52	      return next(new AuthError('Session expired'));
53	    }
54	
55	    const idleMs = now.getTime() - session.lastActivityAt.getTime();
56	    if (idleMs > config.idleTimeoutMs) {
57	      return next(new AuthError('Session idle timeout'));
58	    }
59	
60	    const user = await User.findById(payload.userId);
61	    if (!user || user.accountStatus !== AccountStatus.ACTIVE) {
62	      return next(new AuthError('Account not active'));
63	    }
64	
65	    session.lastActivityAt = now;
66	    await session.save();
67	
68	    req.user = {
69	      userId: payload.userId,
70	      role: user.role,
71	      sessionId: payload.jti,
72	      isAlumni: user.isAlumni,
73	      communityId: user.communityId,
74	      accountStatus: user.accountStatus,
75	    };
76	
77	    next();
78	  } catch (err) {
79	    next(err);
80	  }
81	}
