15	export async function getAuditLogs(req: Request, res: Response, next: NextFunction): Promise<void> {
16	  try {
17	    const { page, limit, action, resource, actorId, from, to } = req.query as any;
18	
19	    const filter: Record<string, any> = {};
20	    if (action) filter.action = action;
21	    if (resource) filter.resource = resource;
22	    if (actorId) filter.actorId = actorId;
23	    if (from || to) {
24	      filter.timestamp = {};
25	      if (from) filter.timestamp.$gte = new Date(from as string);
26	      if (to) filter.timestamp.$lte = new Date(to as string);
27	    }
28	
29	    const skip = ((page as number) - 1) * (limit as number);
30	    const [logs, total] = await Promise.all([
31	      AuditLog.find(filter).sort({ timestamp: -1 }).skip(skip).limit(limit as number),
32	      AuditLog.countDocuments(filter),
33	    ]);
34	
35	    res.status(200).json({
36	      data: logs,
37	      pagination: {
38	        page: page as number,
39	        limit: limit as number,
40	        total,
41	        totalPages: Math.ceil(total / (limit as number)),
42	      },
43	    });
