30	    title: input.title,
31	    description: input.description,
32	    clientId: input.clientId,
33	    communityId: input.communityId,
34	    jobType: input.jobType,
35	    status: JobStatus.DRAFT,
36	    rateType: input.rateType,
37	    agreedRateCents: input.agreedRateCents,
38	    estimatedTotalCents: input.estimatedTotalCents || 0,
39	  });
40	  return job;
41	}
