43	export async function getJobById(jobId: string, requesterId: string) {
44	  const job = await Job.findById(jobId);
45	  if (!job) {
46	    throw new NotFoundError('Job not found');
47	  }
48	  // Look up the requester's role from DB — never trust caller-supplied role
49	  const requester = await User.findById(requesterId);
50	  const requesterRole = requester?.role;
51	
52	  // Object-level authorization: participants, community members with posted jobs, or admins
53	  if (requesterRole !== Role.ADMIN) {
54	    const isParticipant = job.clientId.toString() === requesterId ||
55	      (job.photographerId && job.photographerId.toString() === requesterId);
56	    const isPublicStatus = [JobStatus.POSTED].includes(job.status as JobStatus);
57	    if (!isParticipant && !isPublicStatus) {
58	      throw new ForbiddenError('You do not have access to this job');
59	    }
60	  }
61	  return job;
62	}
