64	export async function updateJob(jobId: string, userId: string, data: Partial<IJob>) {
65	  const job = await Job.findById(jobId);
66	  if (!job) {
67	    throw new NotFoundError('Job not found');
68	  }
69	
70	  if (job.clientId.toString() !== userId) {
71	    throw new ForbiddenError('Only the job client can update the job');
72	  }
73	
74	  if (job.status !== JobStatus.DRAFT && job.status !== JobStatus.POSTED) {
75	    throw new ValidationError('Can only update jobs in draft or posted status');
76	  }
77	
78	  Object.assign(job, data);
79	  await job.save();
80	  return job;
81	}
