83	/**
84	 * Assign a photographer to a job.
85	 * The photographer must have verification status = VERIFIED.
86	 */
87	export async function assignPhotographer(
88	  jobId: string,
89	  photographerId: string,
90	  assignedBy: string,
91	  assignerRole: Role
92	) {
93	  const job = await Job.findById(jobId);
94	  if (!job) {
95	    throw new NotFoundError('Job not found');
96	  }
97	
98	  // Only the job client or an admin can assign
99	  if (job.clientId.toString() !== assignedBy && assignerRole !== Role.ADMIN) {
100	    throw new ForbiddenError('Only the job client or an admin can assign a photographer');
101	  }
102	
103	  if (job.status !== JobStatus.POSTED) {
104	    throw new ValidationError('Can only assign a photographer to a posted job');
105	  }
106	
107	  // Check photographer is verified
108	  const verification = await Verification.findOne({
109	    photographerId,
110	    status: VerificationStatus.VERIFIED,
111	  });
112	
113	  if (!verification) {
114	    throw new ValidationError(
115	      'Photographer must have verified status before being assigned to a job'
116	    );
117	  }
118	
119	  job.photographerId = photographerId as any;
120	  job.status = JobStatus.ASSIGNED;
121	  await job.save();
122	
123	  return job;
124	}
