126	/**
127	 * Transition job status following the state machine rules.
128	 */
129	export async function transitionStatus(
130	  jobId: string,
131	  newStatus: JobStatus,
132	  userId: string,
133	  userRole: Role
134	) {
135	  const job = await Job.findById(jobId);
136	  if (!job) {
137	    throw new NotFoundError('Job not found');
138	  }
139	
140	  // Check user is a participant or admin
141	  const isParticipant =
142	    job.clientId.toString() === userId ||
143	    (job.photographerId && job.photographerId.toString() === userId);
144	
145	  if (!isParticipant && userRole !== Role.ADMIN) {
146	    throw new ForbiddenError('You are not a participant in this job');
147	  }
148	
149	  const allowedTransitions = JOB_STATUS_TRANSITIONS[job.status as JobStatus];
150	  if (!allowedTransitions || !allowedTransitions.includes(newStatus)) {
151	    throw new ValidationError(
152	      `Cannot transition from ${job.status} to ${newStatus}`
153	    );
154	  }
155	
156	  job.status = newStatus;
157	
158	  if (newStatus === JobStatus.COMPLETED) {
159	    job.completedAt = new Date();
160	  }
161	
162	  await job.save();
163	  return job;
164	}
