166	/**
167	 * E-confirm service agreement. Both parties must type their password to confirm.
168	 * The agreement is displayed on-screen and confirmed by re-entering account password.
169	 * Both client and photographer must confirm before the job can proceed to IN_PROGRESS.
170	 */
171	export async function confirmAgreement(
172	  jobId: string,
173	  userId: string,
174	  password: string
175	): Promise<any> {
176	  const job = await Job.findById(jobId);
177	  if (!job) throw new NotFoundError('Job not found');
178	
179	  if (job.status !== JobStatus.ASSIGNED && job.status !== JobStatus.DRAFT && job.status !== JobStatus.POSTED) {
180	    throw new ValidationError('Agreement can only be confirmed on an assigned job');
181	  }
182	
183	  // Verify user is a participant
184	  const isClient = job.clientId.toString() === userId;
185	  const isPhotographer = job.photographerId && job.photographerId.toString() === userId;
186	  if (!isClient && !isPhotographer) {
187	    throw new ForbiddenError('Only job participants can confirm the agreement');
188	  }
189	
190	  // Re-authenticate: verify password against stored hash
191	  const user = await User.findById(userId);
192	  if (!user) throw new AuthError('User not found');
193	  const passwordValid = await user.comparePassword(password);
194	  if (!passwordValid) {
195	    throw new AuthError('Password verification failed. Agreement not confirmed.');
196	  }
197	
198	  // Find or create service agreement
199	  let agreement = await ServiceAgreement.findOne({ jobId });
200	  if (!agreement) {
201	    agreement = await ServiceAgreement.create({
202	      jobId,
203	      version: 1,
204	      content: `Service agreement for job "${job.title}". Agreed rate: ${job.agreedRateCents} cents per ${job.rateType === 'hourly' ? 'hour' : 'unit'}. Both parties agree to the terms of service.`,
205	    });
206	    job.serviceAgreementId = agreement._id as any;
207	  }
208	
209	  // Record confirmation
210	  if (isClient) {
211	    if (agreement.clientConfirmedAt) {
212	      throw new ValidationError('Client has already confirmed this agreement');
213	    }
214	    agreement.clientConfirmedAt = new Date();
215	    job.clientConfirmed = true;
216	  } else if (isPhotographer) {
217	    if (agreement.photographerConfirmedAt) {
218	      throw new ValidationError('Photographer has already confirmed this agreement');
219	    }
220	    agreement.photographerConfirmedAt = new Date();
221	    job.photographerConfirmed = true;
222	  }
223	
224	  await agreement.save();
225	
226	  // If both confirmed, transition to IN_PROGRESS
227	  if (agreement.clientConfirmedAt && agreement.photographerConfirmedAt) {
228	    job.status = JobStatus.IN_PROGRESS;
229	  }
230	
231	  await job.save();
232	
233	  return {
234	    job,
235	    agreement,
236	    clientConfirmed: !!agreement.clientConfirmedAt,
237	    photographerConfirmed: !!agreement.photographerConfirmedAt,
238	    fullyConfirmed: !!(agreement.clientConfirmedAt && agreement.photographerConfirmedAt),
239	  };
240	}
