1	import { Settlement, SettlementLineItem, WorkEntry, Job, User } from '../models';
2	import { SettlementStatus, LineItemType, AdjustmentType, WorkEntryType } from '../types/enums';
3	import { NotFoundError, ValidationError, ForbiddenError } from '../utils/errors';
4	import { addCents, varianceCheck } from '../utils/money';
5	import { beforeSettlementFinalize } from '../hooks/complianceHooks';
6	
7	async function assertSettlementParticipant(settlement: any, actorId: string): Promise<void> {
8	  const actor = await User.findById(actorId);
9	  if (actor?.role === 'admin') return;
10	  const isParticipant =
11	    settlement.clientId.toString() === actorId ||
12	    settlement.photographerId.toString() === actorId;
13	  if (!isParticipant) {
14	    throw new ForbiddenError('Only settlement participants or admins can perform this action');
15	  }
16	}
17	
18	/**
19	 * Generate a settlement by aggregating locked work entries for a job.
20	 */
21	export async function generateSettlement(jobId: string, generatedBy: string) {
22	  const job = await Job.findById(jobId);
23	  if (!job) {
24	    throw new NotFoundError('Job not found');
25	  }
26	
27	  // Only job client, assigned photographer, or admin may generate a settlement
28	  const actor = await User.findById(generatedBy);
29	  if (actor?.role !== 'admin') {
30	    const isParticipant =
31	      job.clientId.toString() === generatedBy ||
32	      (job.photographerId && job.photographerId.toString() === generatedBy);
33	    if (!isParticipant) {
34	      throw new ForbiddenError('Only job participants or admins can generate settlements');
35	    }
36	  }
37	
38	  if (!job.photographerId) {
39	    throw new ValidationError('Job has no assigned photographer');
40	  }
41	
42	  // Get locked work entries
43	  const entries = await WorkEntry.find({ jobId, isLocked: true }).lean();
44	
45	  if (entries.length === 0) {
46	    throw new ValidationError('No locked work entries to settle');
47	  }
48	
49	  // Calculate subtotal
50	  let subtotalCents = 0;
51	  for (const entry of entries) {
52	    subtotalCents = addCents(subtotalCents, entry.subtotalCents);
53	  }
54	
55	  const settlement = await Settlement.create({
56	    jobId,
57	    photographerId: job.photographerId,
58	    clientId: job.clientId,
59	    status: SettlementStatus.DRAFT,
60	    subtotalCents,
61	    adjustmentCents: 0,
62	    finalAmountCents: subtotalCents,
63	  });
64	
65	  // Create line items for each work entry
66	  const lineItems = [];
67	  for (const entry of entries) {
68	    const lineItemType =
69	      entry.entryType === WorkEntryType.TIME
70	        ? LineItemType.TIMESHEET
71	        : LineItemType.PIECE_RATE;
72	
73	    const description =
74	      entry.entryType === WorkEntryType.TIME
75	        ? `Time entry: ${entry.durationMinutes} min on ${entry.date ? new Date(entry.date).toISOString().split('T')[0] : 'N/A'}`
76	        : `Piece rate: ${entry.quantity} x ${entry.itemDescription || 'items'}`;
77	
78	    const lineItem = await SettlementLineItem.create({
79	      settlementId: settlement._id,
80	      description,
81	      amountCents: entry.subtotalCents,
82	      type: lineItemType,
83	      workEntryId: entry._id,
84	      createdBy: generatedBy,
85	    });
86	    lineItems.push(lineItem);
87	  }
88	
89	  return { settlement, lineItems };
90	}
91	
92	/**
93	 * Add an adjustment to a settlement. Type and reason are required.
94	 */
95	export async function addAdjustment(
96	  settlementId: string,
97	  adjustmentType: AdjustmentType,
98	  amountCents: number,
99	  reason: string,
100	  createdBy: string
101	) {
102	  if (!reason || reason.trim().length === 0) {
103	    throw new ValidationError('Adjustment reason is required');
104	  }
105	
106	  const settlement = await Settlement.findById(settlementId);
107	  if (!settlement) {
108	    throw new NotFoundError('Settlement not found');
109	  }
110	
111	  await assertSettlementParticipant(settlement, createdBy);
112	
113	  if (settlement.status !== SettlementStatus.DRAFT && settlement.status !== SettlementStatus.PENDING_REVIEW) {
114	    throw new ValidationError(`Cannot add adjustments to a settlement with status: ${settlement.status}`);
115	  }
116	
117	  const description = `${adjustmentType}: ${reason}`;
118	
119	  const lineItem = await SettlementLineItem.create({
120	    settlementId,
121	    description,
122	    amountCents,
123	    type: LineItemType.ADJUSTMENT,
124	    adjustmentType,
125	    adjustmentReason: reason,
126	    createdBy,
127	  });
128	
129	  // Recalculate settlement totals
130	  settlement.adjustmentCents = addCents(settlement.adjustmentCents, amountCents);
131	  settlement.finalAmountCents = addCents(settlement.subtotalCents, settlement.adjustmentCents);
132	
133	  // Run variance check: threshold = max(subtotal * 0.02, 2500)
134	  const variance = varianceCheck(settlement.subtotalCents, settlement.finalAmountCents);
135	  settlement.variancePercent = variance.variancePercent;
136	  settlement.varianceAmountCents = variance.varianceAmountCents;
137	
138	  await settlement.save();
139	
140	  return { settlement, lineItem };
141	}
142	
143	/**
144	 * Finalize a settlement. Runs variance check and compliance hook.
145	 * Variance threshold = max(subtotal * 0.02, 2500).
146	 * If variance exceeds threshold, a varianceReason is required.
147	 */
148	export async function finalizeSettlement(
149	  settlementId: string,
150	  finalizedBy: string,
151	  varianceReason?: string
152	) {
153	  const settlement = await Settlement.findById(settlementId);
154	  if (!settlement) {
155	    throw new NotFoundError('Settlement not found');
156	  }
157	
158	  await assertSettlementParticipant(settlement, finalizedBy);
159	
160	  if (settlement.status !== SettlementStatus.DRAFT && settlement.status !== SettlementStatus.PENDING_REVIEW) {
161	    throw new ValidationError(`Cannot finalize a settlement with status: ${settlement.status}`);
162	  }
163	
164	  // Run variance check
165	  const variance = varianceCheck(settlement.subtotalCents, settlement.finalAmountCents);
166	
167	  if (variance.requiresReason) {
168	    if (!varianceReason || varianceReason.trim().length === 0) {
169	      throw new ValidationError(
170	        `Variance of ${variance.varianceAmountCents} cents exceeds threshold of ${variance.threshold} cents. A variance reason is required.`
171	      );
172	    }
173	    settlement.varianceReason = varianceReason;
174	  }
175	
176	  settlement.variancePercent = variance.variancePercent;
177	  settlement.varianceAmountCents = variance.varianceAmountCents;
178	
179	  // Run compliance hook
180	  const complianceResult = await beforeSettlementFinalize(settlement.toObject());
181	  if (!complianceResult.allow) {
182	    throw new ForbiddenError(
183	      complianceResult.reason || 'Compliance check failed for settlement finalization'
184	    );
185	  }
186	
187	  settlement.status = SettlementStatus.APPROVED;
188	  await settlement.save();
189	
190	  return settlement;
191	}
192	
193	export async function getSettlement(settlementId: string, requesterId: string) {
194	  const settlement = await Settlement.findById(settlementId);
195	  if (!settlement) {
