85	/**
86	 * Edit a work entry. Resets both confirmations.
87	 */
88	export async function editWorkEntry(
89	  entryId: string,
90	  userId: string,
91	  updates: Partial<CreateWorkEntryInput>
92	) {
93	  const entry = await WorkEntry.findById(entryId);
94	  if (!entry) {
95	    throw new NotFoundError('Work entry not found');
96	  }
97	
98	  if (entry.isLocked) {
99	    throw new ValidationError('Cannot edit a locked work entry');
100	  }
101	
102	  if (entry.photographerId.toString() !== userId) {
103	    throw new ForbiddenError('Only the photographer can edit their work entries');
104	  }
105	
106	  // If duration is being updated, validate alignment
107	  if (updates.durationMinutes !== undefined) {
108	    if (updates.durationMinutes % TIMESHEET_INCREMENT_MINUTES !== 0) {
109	      throw new ValidationError(
110	        `Duration must be in ${TIMESHEET_INCREMENT_MINUTES}-minute increments`
111	      );
112	    }
113	  }
114	
115	  // Recalculate subtotal if relevant fields changed
116	  const job = await Job.findById(entry.jobId);
117	  if (!job) {
118	    throw new NotFoundError('Associated job not found');
119	  }
120	
121	  const entryType = updates.entryType || entry.entryType;
122	  let subtotalCents = entry.subtotalCents;
123	
124	  if (entryType === WorkEntryType.TIME) {
125	    const duration = updates.durationMinutes ?? entry.durationMinutes;
126	    if (duration) {
127	      subtotalCents = calculateTimeEntryCents(job.agreedRateCents, duration);
128	    }
129	  } else {
130	    const quantity = updates.quantity ?? entry.quantity;
131	    const unitRate = updates.unitRateCents ?? entry.unitRateCents ?? job.agreedRateCents;
132	    if (quantity) {
133	      subtotalCents = calculatePieceRateCents(unitRate, quantity);
134	    }
135	  }
136	
137	  // Apply updates and reset confirmations
138	  Object.assign(entry, updates, {
139	    subtotalCents,
140	    clientConfirmedAt: undefined,
141	    photographerConfirmedAt: undefined,
142	    lockAt: undefined,
143	  });
144	
145	  // Use $unset for clearing confirmation dates
146	  await WorkEntry.findByIdAndUpdate(entryId, {
147	    $set: {
148	      ...updates,
149	      subtotalCents,
150	    },
151	    $unset: {
152	      clientConfirmedAt: 1,
153	      photographerConfirmedAt: 1,
154	      lockAt: 1,
155	    },
156	  });
157	
158	  return WorkEntry.findById(entryId);
159	}
160	
161	/**
162	 * Confirm a work entry (bilateral confirmation).
163	 * Client or photographer can confirm.
164	 * Once both confirm, set lockAt = now + 48h.
165	 */
166	export async function confirmWorkEntry(entryId: string, userId: string) {
167	  const entry = await WorkEntry.findById(entryId);
168	  if (!entry) {
169	    throw new NotFoundError('Work entry not found');
170	  }
171	
172	  if (entry.isLocked) {
173	    throw new ValidationError('Work entry is already locked');
174	  }
175	
176	  const job = await Job.findById(entry.jobId);
177	  if (!job) {
178	    throw new NotFoundError('Associated job not found');
179	  }
180	
181	  const isClient = job.clientId.toString() === userId;
182	  const isPhotographer = entry.photographerId.toString() === userId;
183	
184	  if (!isClient && !isPhotographer) {
185	    throw new ForbiddenError('Only the client or photographer can confirm work entries');
186	  }
187	
188	  if (isClient) {
189	    if (entry.clientConfirmedAt) {
190	      throw new ValidationError('Client has already confirmed this entry');
191	    }
192	    entry.clientConfirmedAt = new Date();
193	  }
194	
195	  if (isPhotographer) {
196	    if (entry.photographerConfirmedAt) {
197	      throw new ValidationError('Photographer has already confirmed this entry');
198	    }
199	    entry.photographerConfirmedAt = new Date();
200	  }
201	
202	  // If both confirmed, schedule lock
203	  if (entry.clientConfirmedAt && entry.photographerConfirmedAt) {
204	    const lockAt = new Date();
205	    lockAt.setHours(lockAt.getHours() + LOCK_HOURS);
206	    entry.lockAt = lockAt;
207	  }
208	
209	  await entry.save();
210	  return entry;
211	}
212	
213	/**
214	 * Lock a work entry after 48h from fully confirmed.
215	 */
216	export async function lockWorkEntry(entryId: string) {
217	  const entry = await WorkEntry.findById(entryId);
218	  if (!entry) {
219	    throw new NotFoundError('Work entry not found');
220	  }
221	
222	  if (entry.isLocked) {
223	    return entry; // Already locked, idempotent
224	  }
225	
226	  if (!entry.clientConfirmedAt || !entry.photographerConfirmedAt) {
227	    throw new ValidationError('Work entry must be fully confirmed before locking');
228	  }
229	
230	  if (!entry.lockAt || new Date() < entry.lockAt) {
231	    throw new ValidationError(
232	      `Work entry cannot be locked until ${LOCK_HOURS}h after both parties confirm`
233	    );
234	  }
235	
236	  entry.isLocked = true;
237	  entry.lockedAt = new Date();
238	  await entry.save();
239	  return entry;
240	}
241	
242	export async function getWorkEntriesByJob(jobId: string, requesterId: string) {
243	  const job = await Job.findById(jobId);
244	  if (!job) throw new NotFoundError('Job not found');
245	
246	  const { User } = await import('../models');
247	  const requester = await User.findById(requesterId);
248	  if (requester?.role !== 'admin') {
249	    const isParticipant =
250	      job.clientId.toString() === requesterId ||
251	      (job.photographerId && job.photographerId.toString() === requesterId);
252	    if (!isParticipant) {
253	      throw new ForbiddenError('Only job participants can view work entries');
254	    }
255	  }
256	
257	  return WorkEntry.find({ jobId }).sort({ date: 1, createdAt: 1 }).lean();
258	}
