8	export default function ProfilePage() {
9	  const { id } = useParams<{ id: string }>();
10	  const { user } = useAuth();
11	  const [profile, setProfile] = useState<any>(null);
12	  const [loading, setLoading] = useState(true);
13	  const [error, setError] = useState('');
14	
15	  useEffect(() => {
16	    const fetchProfile = id && id !== 'me'
17	      ? profilesApi.getProfile(id)
18	      : profilesApi.getMyProfile();
19	    fetchProfile
20	      .then(res => setProfile(res.data))
21	      .catch(err => setError(err.response?.data?.msg || 'Failed to load profile'))
22	      .finally(() => setLoading(false));
23	  }, [id]);
24	
25	  if (loading) return <LoadingSpinner message="Loading profile..." />;
26	  if (error) return <div className="bg-red-50 text-red-600 p-4 rounded">{error}</div>;
27	  if (!profile) return <div className="text-gray-500">Profile not found.</div>;
28	
29	  const isOwn = !id || id === 'me' || id === user?._id;
30	  const privacy = profile.privacySettings || {};
31	
32	  const maskValue = (field: string, value: any) => {
33	    if (isOwn) return value || '-';
34	    const level = privacy[field];
35	    if (level === 'alumni_only' && !user?.isAlumni) return '(Alumni only)';
36	    if (level === 'private') {
37	      if (!value) return '-';
38	      const s = String(value);
39	      if (field === 'phone' && s.length >= 7) return `(${s.slice(0, 3)}) ***-${s.slice(-4)}`;
40	      if (field === 'phone') return `(***) ***-${s.slice(-4)}`;
41	      if (field === 'email' && s.includes('@')) {
42	        const [local, domain] = s.split('@');
43	        return `${local[0]}***@${domain}`;
44	      }
45	      if (field === 'employer') return `${s[0]}${'*'.repeat(Math.min(s.length - 1, 8))}`;
46	      return '******';
47	    }
48	    return value || '-';
49	  };
50	
51	  const fields = [
52	    { label: 'First Name', key: 'firstName' },
53	    { label: 'Last Name', key: 'lastName' },
54	    { label: 'Email', key: 'email' },
55	    { label: 'Phone', key: 'phone' },
56	    { label: 'Location', key: 'location' },
57	    { label: 'Employer', key: 'employer' },
58	    { label: 'Bio', key: 'bio' },
59	    { label: 'Graduation Year', key: 'graduationYear' },
60	  ];
61	
62	  return (
63	    <div>
64	      <div className="flex items-center justify-between mb-6">
65	        <h1 className="text-2xl font-bold">
66	          {isOwn ? 'My Profile' : `${profile.firstName || ''} ${profile.lastName || ''}`.trim() || 'Profile'}
67	        </h1>
68	        {isOwn && (
69	          <Link to="/profile/edit" className="bg-primary-600 text-white px-4 py-2 rounded hover:bg-primary-700 text-sm">
70	            Edit Profile
71	          </Link>
72	        )}
73	      </div>
74	      <div className="bg-white rounded-lg shadow">
75	        <dl className="divide-y">
76	          {fields.map(f => (
77	            <div key={f.key} className="px-6 py-4 sm:grid sm:grid-cols-3 sm:gap-4">
78	              <dt className="text-sm font-medium text-gray-500">{f.label}</dt>
79	              <dd className="mt-1 text-sm text-gray-900 sm:col-span-2 sm:mt-0">
80	                {maskValue(f.key, profile[f.key])}
81	                {!isOwn && privacy[f.key] && privacy[f.key] !== 'public' && (
82	                  <StatusBadge status={privacy[f.key]} size="sm" />
83	                )}
84	              </dd>
85	            </div>
86	          ))}
87	        </dl>
88	      </div>
89	    </div>
90	  );
91	}
