3	// Extracted maskValue logic for unit testing (mirrors ProfilePage.tsx)
4	function maskValue(
5	  field: string,
6	  value: any,
7	  isOwn: boolean,
8	  privacyLevel: string | undefined,
9	  isAlumni: boolean
10	): string {
11	  if (isOwn) return value || '-';
12	  if (privacyLevel === 'alumni_only' && !isAlumni) return '(Alumni only)';
13	  if (privacyLevel === 'private') {
14	    if (!value) return '-';
15	    const s = String(value);
16	    if (field === 'phone' && s.length >= 7) return `(${s.slice(0, 3)}) ***-${s.slice(-4)}`;
17	    if (field === 'phone') return `(***) ***-${s.slice(-4)}`;
18	    if (field === 'email' && s.includes('@')) {
19	      const [local, domain] = s.split('@');
20	      return `${local[0]}***@${domain}`;
21	    }
22	    if (field === 'employer') return `${s[0]}${'*'.repeat(Math.min(s.length - 1, 8))}`;
23	    return '******';
24	  }
25	  return value || '-';
26	}
