1	const http = require('http');
2	const crypto = require('crypto');
3	
4	const BASE = process.env.API_BASE || 'http://server:3001';
5	const MONGO_URI = process.env.MONGODB_URI || 'mongodb://mongo:27017/lenswork';
6	
7	function request(method, path, body, token) {
8	  return new Promise((resolve, reject) => {
9	    const url = new URL(path, BASE);
10	    const nonce = crypto.randomUUID();
11	    const timestamp = Date.now().toString();
12	    const options = {
13	      hostname: url.hostname,
14	      port: url.port,
15	      path: url.pathname,
16	      method,
17	      headers: {
18	        'Content-Type': 'application/json',
19	        'X-Nonce': nonce,
20	        'X-Timestamp': timestamp,
21	      },
22	    };
23	    if (token) options.headers['Authorization'] = `Bearer ${token}`;
24	    const req = http.request(options, (res) => {
25	      let data = '';
26	      res.on('data', chunk => data += chunk);
27	      res.on('end', () => {
28	        try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
29	        catch { resolve({ status: res.statusCode, data }); }
30	      });
31	    });
32	    req.on('error', reject);
33	    if (body) req.write(JSON.stringify(body));
34	    req.end();
35	  });
36	}
