26	export async function register(input: RegisterInput) {
27	  // Validate password strength
28	  if (!input.password || input.password.length < 8) {
29	    throw new ValidationError('Password must be at least 8 characters');
30	  }
31	  if (!/[A-Z]/.test(input.password)) {
32	    throw new ValidationError('Password must contain an uppercase letter');
33	  }
34	  if (!/[a-z]/.test(input.password)) {
35	    throw new ValidationError('Password must contain a lowercase letter');
36	  }
37	  if (!/[0-9]/.test(input.password)) {
38	    throw new ValidationError('Password must contain a number');
39	  }
40	
41	  const existingUser = await User.findOne({
42	    $or: [{ email: input.email.toLowerCase() }, { username: input.username }],
43	  });
44	
45	  if (existingUser) {
46	    throw new ConflictError('A user with that email or username already exists');
47	  }
48	
49	  // Defence-in-depth: never allow self-registration as admin
50	  if (input.role === Role.ADMIN) {
51	    throw new ValidationError('Cannot self-assign admin role');
52	  }
53	
54	  const user = await User.create({
55	    username: input.username,
56	    email: input.email.toLowerCase(),
57	    passwordHash: input.password,
58	    role: input.role || Role.ALUMNI,
59	    isAlumni: input.isAlumni !== undefined ? input.isAlumni : true,
60	    communityId: input.communityId || 'default',
61	  });
62	
63	  const profile = await Profile.create({
64	    userId: user._id,
65	    firstName: input.firstName || '',
66	    lastName: input.lastName || '',
67	    email: input.email.toLowerCase(),
68	  });
69	
70	  const { token, jti, expiresAt } = issueToken(user._id!.toString(), user.role);
71	  await Session.create({
72	    userId: user._id,
73	    jti,
74	    issuedAt: new Date(),
75	    lastActivityAt: new Date(),
76	    absoluteExpiry: expiresAt,
77	  });
78	
79	  return { user, profile, token };
80	}
