82	export async function login(input: any) {
83	  const query = input.username
84	    ? { username: input.username }
85	    : { email: (input.email || '').toLowerCase() };
86	  const user = await User.findOne(query);
87	
88	  if (!user) {
89	    await logEvent({
90	      action: AUDIT_EVENTS.LOGIN_FAILURE,
91	      resource: 'auth',
92	      details: { email: input.email, reason: 'user_not_found' },
93	      ipAddress: input.ipAddress,
94	      outcome: 'failure',
95	    });
96	    throw new AuthError('Invalid email or password');
97	  }
98	
99	  if (user.accountStatus === AccountStatus.BANNED) {
100	    await logEvent({
101	      actorId: user._id.toString(),
102	      actorRole: user.role,
103	      action: AUDIT_EVENTS.LOGIN_FAILURE,
104	      resource: 'auth',
105	      resourceId: user._id.toString(),
106	      details: { reason: 'account_banned' },
107	      ipAddress: input.ipAddress,
108	      outcome: 'failure',
109	    });
110	    throw new ForbiddenError('This account has been banned');
111	  }
112	
113	  if (user.accountStatus === AccountStatus.SUSPENDED) {
114	    await logEvent({
115	      actorId: user._id.toString(),
116	      actorRole: user.role,
117	      action: AUDIT_EVENTS.LOGIN_FAILURE,
118	      resource: 'auth',
119	      resourceId: user._id.toString(),
120	      details: { reason: 'account_suspended' },
121	      ipAddress: input.ipAddress,
122	      outcome: 'failure',
123	    });
124	    throw new ForbiddenError('This account is currently suspended');
125	  }
126	
127	  const isMatch = await user.comparePassword(input.password);
128	  if (!isMatch) {
129	    user.failedLoginAttempts += 1;
130	    await user.save();
131	
132	    await logEvent({
133	      actorId: user._id.toString(),
134	      actorRole: user.role,
135	      action: AUDIT_EVENTS.LOGIN_FAILURE,
136	      resource: 'auth',
137	      resourceId: user._id.toString(),
138	      details: { reason: 'invalid_password', attempts: user.failedLoginAttempts },
139	      ipAddress: input.ipAddress,
140	      outcome: 'failure',
141	    });
142	    throw new AuthError('Invalid email or password');
143	  }
144	
145	  // Successful login — reset failed attempts
146	  user.failedLoginAttempts = 0;
147	  user.lastLoginAt = new Date();
148	  user.lastActivityAt = new Date();
149	  await user.save();
150	
151	  const { token, jti, expiresAt } = issueToken(user._id.toString(), user.role);
152	
153	  const session = await Session.create({
154	    userId: user._id,
155	    jti,
156	    deviceFingerprint: input.deviceFingerprint,
157	    issuedAt: new Date(),
158	    lastActivityAt: new Date(),
159	    absoluteExpiry: expiresAt,
160	  });
161	
162	  await logEvent({
163	    actorId: user._id.toString(),
164	    actorRole: user.role,
165	    action: AUDIT_EVENTS.LOGIN_SUCCESS,
166	    resource: 'auth',
167	    resourceId: user._id.toString(),
168	    ipAddress: input.ipAddress,
169	    deviceFingerprint: input.deviceFingerprint,
170	    outcome: 'success',
171	  });
172	
173	  return { user, token, session };
174	}
