5	function multipartUpload(url, token, fields, fileField) {
6	  const boundary = '----TestBound' + Date.now();
7	  const parts = [];
8	  for (const [name, value] of Object.entries(fields)) {
9	    parts.push(Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="${name}"\r\n\r\n${value}\r\n`));
10	  }
11	  if (fileField) {
12	    parts.push(Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="${fileField.name}"; filename="${fileField.filename}"\r\nContent-Type: ${fileField.contentType}\r\n\r\n`));
13	    parts.push(fileField.buffer);
14	    parts.push(Buffer.from('\r\n'));
15	  }
16	  parts.push(Buffer.from(`--${boundary}--`));
17	  const body = Buffer.concat(parts);
18	
19	  return new Promise((resolve, reject) => {
20	    const parsed = new URL(url, process.env.API_BASE || 'http://server:3001');
21	    const req = http.request({
22	      hostname: parsed.hostname, port: parsed.port, path: parsed.pathname, method: 'POST',
23	      headers: {
24	        'Content-Type': `multipart/form-data; boundary=${boundary}`,
25	        'Content-Length': body.length,
26	        'Authorization': `Bearer ${token}`,
27	        'X-Nonce': crypto.randomUUID(),
28	        'X-Timestamp': Date.now().toString(),
29	      },
30	    }, (res) => {
31	      let data = '';
32	      res.on('data', chunk => data += chunk);
33	      res.on('end', () => {
34	        try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
35	        catch { resolve({ status: res.statusCode, data }); }
36	      });
37	    });
38	    req.on('error', reject);
39	    req.write(body);
40	    req.end();
41	  });
42	}
